from typing import Iterable, Sequence, Optional, List

import numpy as np
from geosat.cloud import PointCloud
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from geosat.psanp.abstractions.stage import Stage

from psanp.classifiers.sequence_classifier import SequenceClassifier


class AugmentationClassifier(SequenceClassifier):
    """A classifier that implements test-time augmentation:

    https://medium.com/data-science/test-time-augmentation-tta-and-how-to-perform-it-with-keras-4ac19b67fb4d

    It executes a sequence of stages on a point cloud multiple times.
    A small arbitrary non-destructive transformation (rotation on the XY plane and
    XYZ translation) is applied to the point cloud before each execution.
    The classification results are merged by selecting the most common class
    for each point. It can help to reduce voxelization artifacts at the cost of a
    longer inference time.
    """

    def __init__(
        self,
        stages: Sequence[Stage] = (),
        iterations: int = 3,
        seed: int = 42,
        stage_name: Optional[str] = None,
    ) -> None:
        super().__init__(stages, stage_name)
        if iterations < 0:
            raise ValueError("'iterations' option must be positive or null")
        self.iterations = iterations
        self.seed = seed

    @classmethod
    def options(cls) -> List[Option]:
        return [
            *super().options(),
            Option(
                "iterations",
                description="The number of iterations to run. Prefer odd numbers to "
                "avoid equalities when selecting the most common class for each point. "
                "Setting to 0 will return the point cloud unchanged. Setting to 1 has "
                "the same effect as directly executing the stages",
                type_cast=int,
                required=False,
            ),
            Option(
                "seed",
                description="The seed to use for the random number generator for "
                "the transformations to apply",
                type_cast=int,
                required=False,
            ),
        ]

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        if not cloud or self.iterations <= 0:
            return (cloud,)
        if self.iterations == 1:  # Optimization
            return super().execute_on(cloud, pipeline_metadata)
        rng = np.random.default_rng(seed=self.seed)
        classifications = np.zeros((len(cloud), self.iterations), dtype=np.uint8)
        original_classification = cloud.classification.copy()
        for i in range(self.iterations):
            if i == 0:  # Optimization: the first cloud does not need to be transformed
                transformed_cloud = cloud
            else:
                angle = 2 * np.pi * rng.random()
                offset = rng.normal(scale=0.1, size=3)
                c = np.cos(angle)
                s = np.sin(angle)
                matrix = np.array([[c, -s, 0.0], [s, c, 0.0], [0.0, 0.0, 1.0]])
                center = (cloud.bb_max() - cloud.bb_min()) / 2
                transformed_coords = (cloud.coords - center) @ matrix
                transformed_coords += offset
                transformed_cloud = PointCloud(
                    transformed_coords,
                    fields=cloud.fields,  # No copy to optimize memory
                    metadata=cloud.metadata,
                )
            (transformed_cloud,) = super().execute_on(
                transformed_cloud, pipeline_metadata
            )
            classifications[:, i] = transformed_cloud.classification
            # The classification of `cloud` has been modified as a side-effect
            # It must be restored:
            cloud.classification[:] = original_classification
        most_common_class = np.array(
            [np.bincount(classes).argmax() for classes in classifications],
            dtype=np.uint8,
        )
        cloud.classification[:] = most_common_class
        return (cloud,)
